# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_uploaded_file(filename, uploads_dir='uploads'):
    file_path = os.path.join(uploads_dir, filename)
    if os.path.isfile(file_path):
        try:
            os.remove(file_path)
            return True
        except Exception as e:
            print(f"Error deleting file: {e}")
            return False
    else:
        print("File does not exist.")
        return False
